#include <stdio.h>
#include <math.h>

int main() {
    // System configuration
    unsigned int address_bits = 16;    // Address bus width
    unsigned int word_bits = 16;        // Word size in bits
    unsigned int byte_address = 1000;   // Byte address to convert

    // Calculate capacities
    unsigned long addressable_bytes = pow(2, address_bits);
    unsigned long memory_capacity = addressable_bytes * (word_bits / 8);

    printf("=== Memory Organization Calculator ===\n");
    printf("Address bits: %d\n", address_bits);
    printf("Word size: %d bits\n", word_bits);
    printf("Addressable locations: %lu\n", addressable_bytes);
    printf("Total memory capacity: %lu bytes (%.2f KB)\n", 
           memory_capacity, memory_capacity/1024.0);

    // Convert byte address to word address
    unsigned int word_address = byte_address / (word_bits / 8);
    unsigned int byte_offset = byte_address % (word_bits / 8);

    printf("\nByte Address: %d\n", byte_address);
    printf("Word Address: %d\n", word_address);
    printf("Byte Offset within word: %d\n", byte_offset);

    return 0;
}
